document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".faq-list__item-header--js").forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".faq-list__item");t&&t.classList.toggle("active")})}),document.querySelectorAll(".focus-card__dropdown-button button").forEach(e=>{e.addEventListener("click",()=>{if(!(window.innerWidth<1024))return;const t=e.closest(".focus-card");t&&(t.classList.toggle("focus-card--hidden-mobile"),t.classList.toggle("active"))})})});